import{_ as a,o as i,c as s,ag as n}from"./chunks/framework.CO1DiHOz.js";const u=JSON.parse('{"title":"Azure OpenAI","description":"","frontmatter":{},"headers":[],"relativePath":"providers/azure.md","filePath":"providers/azure.md","rawMarkdown":"# Azure OpenAI\\n\\n**Provider value:** `azure`\\n\\nAzure OpenAI runs the same models as OpenAI but through your own Azure resource, with Azure\'s authentication and compliance guarantees. ra uses `AzureOpenAI` from the `openai` SDK and supports both API key and `DefaultAzureCredential` authentication.\\n\\n## Setup\\n\\n**Option 1: API key**\\n\\n```bash\\nexport AZURE_OPENAI_API_KEY=your-azure-api-key\\nexport AZURE_OPENAI_ENDPOINT=https://myresource.openai.azure.com/\\nexport AZURE_OPENAI_DEPLOYMENT=my-gpt4o\\nra --provider azure \\"Hello\\"\\n```\\n\\n**Option 2: DefaultAzureCredential** (recommended for Azure-hosted workloads)\\n\\nWhen `AZURE_OPENAI_API_KEY` is not set, ra falls back to `DefaultAzureCredential`, which tries these in order:\\n\\n1. `AZURE_CLIENT_ID` / `AZURE_CLIENT_SECRET` / `AZURE_TENANT_ID` env vars\\n2. Workload identity (AKS)\\n3. Managed identity (Azure VMs, App Service, Container Apps)\\n4. Azure CLI (`az login`)\\n5. Azure Developer CLI (`azd auth login`)\\n\\n```bash\\nexport AZURE_OPENAI_ENDPOINT=https://myresource.openai.azure.com/\\nexport AZURE_OPENAI_DEPLOYMENT=my-gpt4o\\nra --provider azure \\"Hello\\"\\n```\\n\\n## Environment variables\\n\\nCredentials are env-only â€” never passed as CLI flags to keep them out of shell history.\\n\\n| Variable | Required | Description |\\n|----------|----------|-------------|\\n| `AZURE_OPENAI_ENDPOINT` | Yes | Azure OpenAI resource endpoint |\\n| `AZURE_OPENAI_DEPLOYMENT` | Yes | Deployment name (as configured in Azure AI Studio) |\\n| `AZURE_OPENAI_API_KEY` | No | API key auth. Omit to use `DefaultAzureCredential` |\\n\\nThe API version can be set in a config file:\\n\\n```yaml\\napp:\\n  providers:\\n    azure:\\n      apiVersion: 2024-12-01-preview\\n```\\n\\n## CLI flags\\n\\nNon-sensitive options can also be set via CLI:\\n\\n| Flag | Description |\\n|------|-------------|\\n| `--azure-endpoint` | Azure resource endpoint |\\n| `--azure-deployment` | Deployment name |\\n\\n## Config file\\n\\n```yaml\\napp:\\n  providers:\\n    azure:\\n      endpoint: https://myresource.openai.azure.com/\\n      deployment: my-gpt4o\\n      apiVersion: 2024-12-01-preview\\nagent:\\n  provider: azure\\n```\\n\\n## Deployment vs model\\n\\nIn Azure OpenAI, you deploy a model under a name you choose (e.g. `my-gpt4o`). ra uses the deployment name for all API calls â€” the `--model` flag is ignored when using Azure. Set your deployment via `AZURE_OPENAI_DEPLOYMENT` or `--azure-deployment`.\\n\\n## Extended thinking\\n\\nSupported levels: `low`, `medium`, `high` (requires a reasoning-capable deployment).\\n\\n```bash\\nra --provider azure --thinking medium \\"Analyze this architecture\\"\\n```\\n\\n## See also\\n\\n- [Context Control](/core/context-control) â€” extended thinking details\\n- [Configuration](/configuration/) â€” provider credentials reference\\n"}'),t={name:"providers/azure.md"};function r(l,e,o,p,h,d){return i(),s("div",null,[...e[0]||(e[0]=[n("",27)])])}const c=a(t,[["render",r]]);export{u as __pageData,c as default};
